<template>
  <IosCard
    :title="t('tools_npc_gen')"
    icon="fa-solid fa-users"
    icon-color="#ffc107"
    hide-header
    :collapsible="false"
  >
    <div
      style="
        background: rgba(255, 193, 7, 0.12);
        border: 1px solid rgba(255, 193, 7, 0.3);
        border-radius: 12px;
        padding: 14px 16px;
        margin-bottom: 20px;
        display: flex;
        align-items: flex-start;
        gap: 10px;
        color: #ffd666;
        font-size: 14px;
      "
    >
      <i class="fa-solid fa-info-circle" style="margin-top: 2px"></i>
      <span>快速生成配角 NPC 设定，读取当前角色卡和世界书作为背景参考。</span>
    </div>

    <!-- 背景参考 -->
    <div style="margin-bottom: 20px">
      <label
        style="
          display: block;
          font-size: 13px;
          font-weight: 500;
          color: rgba(235, 235, 245, 0.6);
          margin-bottom: 8px;
          text-transform: uppercase;
          letter-spacing: 0.5px;
        "
        >读取背景参考（可选）</label
      >
      <div style="display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 12px">
        <IosButton size="sm" icon="fa-solid fa-id-card" @click="loadContext('char')"> 当前角色卡 </IosButton>
        <IosSelect
          v-model="selectedWorldbook"
          :options="worldbookOptions"
          placeholder="从世界书读取…"
          style="min-width: 180px"
          @update:model-value="loadContext('worldbook')"
        />
        <IosButton v-if="context" size="sm" variant="danger" icon="fa-solid fa-times" @click="context = ''">
          清除背景
        </IosButton>
      </div>

      <div
        v-if="context"
        style="
          margin-top: 8px;
          padding: 10px;
          background: #1c1c1e;
          border: 1px solid rgba(84, 84, 88, 0.4);
          border-radius: 8px;
          max-height: 80px;
          overflow-y: auto;
          font-size: 12px;
          color: rgba(235, 235, 245, 0.6);
          line-height: 1.5;
        "
      >
        <p style="margin: 0">{{ context.substring(0, 200) }}{{ context.length > 200 ? '...' : '' }}</p>
      </div>
    </div>

    <!-- 模板选择 -->
    <div style="margin-bottom: 20px">
      <label
        style="
          display: block;
          font-size: 13px;
          font-weight: 500;
          color: rgba(235, 235, 245, 0.6);
          margin-bottom: 8px;
          text-transform: uppercase;
          letter-spacing: 0.5px;
        "
        >输出模板</label
      >
      <div style="display: flex; gap: 8px; flex-wrap: wrap">
        <label
          v-for="tpl in templates"
          :key="tpl.value"
          :style="{
            display: 'flex',
            flexDirection: 'column',
            padding: '10px 14px',
            background: templateType === tpl.value ? 'rgba(255,193,7,0.15)' : '#2c2c2e',
            border: templateType === tpl.value ? '1px solid #ffc107' : '1px solid rgba(84,84,88,0.4)',
            borderRadius: '12px',
            cursor: 'pointer',
            minWidth: '120px',
            transition: 'all 0.25s ease',
          }"
        >
          <input v-model="templateType" type="radio" :value="tpl.value" style="display: none" />
          <span style="color: #fff; font-size: 13px; font-weight: 500">{{ tpl.label }}</span>
          <span style="color: rgba(235, 235, 245, 0.6); font-size: 11px; margin-top: 4px">{{ tpl.desc }}</span>
        </label>
      </div>
    </div>

    <!-- NPC 描述 -->
    <div style="margin-bottom: 20px">
      <label
        style="
          display: block;
          font-size: 13px;
          font-weight: 500;
          color: rgba(235, 235, 245, 0.6);
          margin-bottom: 8px;
          text-transform: uppercase;
          letter-spacing: 0.5px;
        "
        >NPC 描述（简短即可）</label
      >
      <IosTextarea
        v-model="description"
        placeholder="例如：酒馆老板，中年男性，健谈，知道很多八卦，对主角有好感"
        :rows="3"
      />
    </div>

    <!-- 进度条 -->
    <div v-if="isProcessing && progress > 0" style="margin: 20px 0">
      <div style="width: 100%; height: 6px; background: #3a3a3c; border-radius: 9999px; overflow: hidden">
        <div
          :style="{
            width: progress + '%',
            height: '100%',
            background: '#ffc107',
            borderRadius: '9999px',
            transition: 'width 0.3s ease',
          }"
        ></div>
      </div>
      <p style="text-align: center; margin-top: 8px; color: #ffc107; font-size: 13px">
        生成中... {{ progress.toFixed(0) }}%
      </p>
    </div>

    <!-- 按钮 -->
    <div style="display: flex; gap: 12px; margin-bottom: 20px">
      <IosButton
        variant="primary"
        :disabled="isProcessing || !description.trim()"
        :loading="isProcessing"
        icon="fa-solid fa-magic"
        style="background: #ffc107; color: black"
        @click="handleGenerate"
      >
        {{ isProcessing ? '生成中...' : '生成 NPC' }}
      </IosButton>
      <IosButton icon="fa-solid fa-trash" @click="clearForm"> 清空 </IosButton>
    </div>

    <!-- 输出区域 -->
    <div v-if="output" style="margin-top: 24px">
      <div style="display: flex; align-items: center; gap: 8px; margin-bottom: 12px">
        <i class="fa-solid fa-check-circle" style="color: #30d158"></i>
        <span style="font-size: 15px; font-weight: 600; color: #fff">生成的 NPC</span>
      </div>

      <div
        style="
          background: #1c1c1e;
          border: 1px solid rgba(84, 84, 88, 0.4);
          border-radius: 12px;
          padding: 16px;
          color: #e0e0e0;
          font-size: 14px;
          line-height: 1.6;
          white-space: pre-wrap;
          word-wrap: break-word;
          max-height: 300px;
          overflow-y: auto;
        "
      >
        {{ output }}
      </div>

      <div style="margin-top: 16px; display: flex; gap: 12px; flex-wrap: wrap">
        <IosButton icon="fa-solid fa-copy" @click="copyResult"> 复制 </IosButton>
        <div style="flex: 1; min-width: 180px; display: flex; gap: 8px">
          <IosSelect
            v-model="insertWorldbook"
            :options="worldbookOptions"
            placeholder="插入到世界书..."
            style="flex: 1"
          />
          <IosButton v-if="insertWorldbook" icon="fa-solid fa-download" @click="insertToWorldbook"> 插入 </IosButton>
        </div>
      </div>
    </div>
  </IosCard>
</template>

<script setup lang="ts">
import { storeToRefs } from 'pinia';
import { computed, ref, watch } from 'vue';
import { useI18n } from '../../i18n';
import { useSettingsStore } from '../../settings';
import { copyToClipboard } from '../../utils';
import { callAIWithTavernSupport } from '../../utils/api';
import { translateError } from '../../utils/error-handler';
import { IosButton, IosCard, IosSelect, IosTextarea } from '../ios';

const { t } = useI18n();
const settingsStore = useSettingsStore();
const { settings } = storeToRefs(settingsStore);

// Props
const props = defineProps<{
  availableWorldbooks: string[];
}>();

// Emits
const emit = defineEmits<{
  (e: 'dataChange', data: any): void;
}>();

// 状态
const expanded = ref(true);
const description = ref('');
const output = ref('');
const context = ref('');
const isProcessing = ref(false);
const progress = ref(0);
const templateType = ref<'simple' | 'detailed' | 'dialogue'>('simple');
const selectedWorldbook = ref('');
const insertWorldbook = ref('');

// 世界书选项
const worldbookOptions = computed(() => props.availableWorldbooks.map(wb => ({ value: wb, label: wb })));

// 模板选项
const templates = [
  { value: 'simple', label: '简洁版', desc: '姓名+外貌+性格+关系' },
  { value: 'detailed', label: '详细版', desc: '完整设定含背景故事' },
  { value: 'dialogue', label: '对话风格', desc: '含口头禅和说话方式' },
] as const;

// 监听数据变化
watch(
  [description, output, templateType],
  () => {
    emit('dataChange', {
      description: description.value,
      output: output.value,
      templateType: templateType.value,
    });
  },
  { deep: true },
);

// 读取背景
const loadContext = async (source: 'char' | 'worldbook') => {
  try {
    const tav = (window as any).TavernHelper;

    if (source === 'char') {
      if (tav?.getCharData) {
        const char = tav.getCharData('current');
        if (char) {
          let content = `【角色信息】\n角色名：${char.name || '未知'}\n`;
          const desc = char.description || char.data?.description;
          if (desc) content += `描述：${desc}\n`;
          const personality = char.personality || char.data?.personality;
          if (personality) content += `性格：${personality}\n`;
          context.value = content;
          window.toastr.success('已读取角色卡');
        } else {
          window.toastr.warning('请先选择一个角色');
        }
      }
    } else if (source === 'worldbook' && selectedWorldbook.value) {
      if (tav?.getWorldbook) {
        const entries = await tav.getWorldbook(selectedWorldbook.value);
        if (entries?.length) {
          const content = entries
            .filter((e: any) => e.content)
            .map((e: any) => `【${e.name || e.comment || '条目'}】\n${e.content}`)
            .join('\n\n');
          context.value = content;
          window.toastr.success(`已读取 ${entries.length} 个条目`);
        }
      }
      selectedWorldbook.value = '';
    }
  } catch (e) {
    console.error('读取失败:', e);
    window.toastr.error('读取失败');
  }
};

// 获取 Prompt
const getPrompt = (): string => {
  const contextBlock = context.value ? `【背景参考】\n${context.value}\n\n` : '';

  const templatePrompts: Record<string, string> = {
    simple: `输出格式：
【姓名】xxx
【外貌】简短描述外貌特征
【性格】简短描述性格特点
【与主角的关系】简短说明`,
    detailed: `输出格式：
【姓名】xxx
【外貌】详细描述外貌特征
【性格】详细描述性格特点
【背景故事】简短的背景故事
【与主角的关系】关系说明
【特殊技能/爱好】如有`,
    dialogue: `输出格式：
【姓名】xxx
【外貌】简短描述
【性格】简短描述
【说话风格】描述说话方式和口头禅
【常用台词】列出2-3句典型台词`,
  };

  return `你是一个专业的配角 NPC 设计师。根据用户的描述生成 NPC 角色设定。

${contextBlock}${templatePrompts[templateType.value]}

要求：
1. 严格按照上面的格式输出
2. 风格自然，避免八股套话
3. 直接输出内容，不要解释`;
};

// 处理生成
const handleGenerate = async () => {
  if (!description.value.trim()) {
    window.toastr.warning('请输入 NPC 描述');
    return;
  }

  try {
    isProcessing.value = true;
    progress.value = 0;
    window.toastr.info('正在生成 NPC...');

    const messages = [
      { role: 'system', content: getPrompt() },
      { role: 'user', content: `请根据以下描述生成 NPC：\n${description.value}` },
    ];

    const result = await callAIWithTavernSupport(
      messages,
      {
        ...settings.value,
      },
      {
        onProgress: (p: number) => (progress.value = p),
      },
    );

    output.value = result;
    window.toastr.success('NPC 生成完成！');
  } catch (error) {
    console.error('NPC 生成失败:', error);
    window.toastr.error(translateError(error, 'NPC 生成'));
  } finally {
    isProcessing.value = false;
    progress.value = 0;
  }
};

// 复制结果
const copyResult = () => {
  if (!output.value) return;
  copyToClipboard(output.value, 'NPC 已复制');
};

// 插入世界书
const insertToWorldbook = async () => {
  if (!output.value || !insertWorldbook.value) return;

  try {
    const tav = (window as any).TavernHelper;
    if (tav?.createWorldbookEntries) {
      // 从输出中提取名字
      const nameMatch = output.value.match(/【姓名】(.+)/);
      const name = nameMatch ? nameMatch[1].trim() : 'NPC';

      await tav.createWorldbookEntries(insertWorldbook.value, [
        {
          name: name,
          content: output.value,
          keys: [name],
          comment: '由猫猫工具自动生成',
          enabled: true,
        },
      ]);
      window.toastr.success('已插入到世界书');
      insertWorldbook.value = '';
    }
  } catch (e) {
    console.error('插入失败:', e);
    window.toastr.error('插入失败');
  }
};

// 清空
const clearForm = () => {
  description.value = '';
  output.value = '';
  context.value = '';
};

// 暴露方法
defineExpose({
  setExpanded: (val: boolean) => (expanded.value = val),
  loadData: (data: any) => {
    if (data) {
      description.value = data.description || '';
      output.value = data.output || '';
      templateType.value = data.templateType || 'simple';
    }
  },
});
</script>
